{"type":"FlowTopic","triggers":[{"type":"Trigger","name":"4196c869802e493db71ab899f1cb5f40","triggerType":"request","applicability":{"type":"Applicability","mode":"script","value":"true"},"id":"4196c869802e493db71ab899f1cb5f40"}],"goals":[{"name":"primary","trigger_id":"4196c869802e493db71ab899f1cb5f40","nodes":[{"type":"StartGoal","goal_id":"primary","greeting_msg":{"type":"String","mode":"string","value":""},"id":"fd68c84cb92f41a9bd71541c87f5dea9","name":"Start","expert_mode":false},{"type":"TerminateGoal","goal_id":"primary","confirmation_msg":{"type":"String","mode":"string","value":""},"id":"f6e35f9482734e7bac7a9b01bc0badf3","name":"End","expert_mode":false},{"type":"ScriptedAction","script":"(function execute() {

 try {

 var query = "";

 // ✅ Safe read from VA input
 if (typeof vaInputs !== 'undefined' && vaInputs.user_input) {
 query = vaInputs.user_input;
 }

 // ✅ Fallback (VERY IMPORTANT)
 if ((!query || query === "") && typeof vaVars !== 'undefined' && vaVars._topic_current_message) {
 query = vaVars._topic_current_message;
 }

 // ✅ Final fallback to avoid crash
 if (!query) {
 query = "payout";
 }

 var userId = gs.getUserID();

 var service = new x_ctans_incentnow.IncentNowCopilotService();
 var response = service.getResponse(query, userId);

 vaVars.gptResponse = response;

 } catch (ex) {

 gs.error("FINAL VA ERROR: " + ex.message);

 vaVars.gptResponse = "⚠️ Something went wrong. Please try again.";
 }

})();","id":"7a4bd2c534984ff29d26ca6e58d7c309","name":"Script","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false},{"type":"InputPrompt","variable_id":"1fabddb00f784b1a861fa32458efd900","message":{"type":"String","mode":"string","value":"gs.getMessageLang("How can I help you with your incentives today?", vaContext.getRequesterLang())"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_confirmation_prompt":true},"request_feedback":true,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"metadataScript":"","cardName":"","cardFields":[],"id":"74ab4fba40aa48eaba1bfbccc050dac4","name":"user Input","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"formatType":"Text","validationScript":"","description":""},{"type":"TextOutputPrompt","value":[{"type":"String","mode":"string","value":"{{vaVars.gptResponse}}"}],"request_feedback":true,"isCollapsible":true,"id":"9303fb11360649798f8315d69935fd5e","name":"Bot response","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"secure":false},{"type":"ChoiceInputPrompt","expression_mode":"simple","metadataScript":"","cardName":"","cardFields":[],"id":"fe8bef208433449fb182e7a7a47b190b","name":"User choice","goal_id":"primary","applicability":{"type":"Applicability","mode":"script","value":"true"},"expert_mode":false,"variable_id":"faf7927d55f74bd498643eb52138dbb0","message":{"type":"String","mode":"string","value":"gs.getMessageLang("Do you have any other Questions?", vaContext.getRequesterLang())"},"request_feedback":false,"skippable":{"type":"Applicability","mode":"script","value":"false"},"skipreprompt":{"type":"Applicability","mode":"script","value":"false"},"nlu_entity_binding":{"type":"NLUEntityBinding","allow_text_input":false,"use_c